/**
 * Bulk Image Fix Script
 * Fetches Google Places photos for all places with missing/bad images.
 * Reads from tmp/places_needing_images.json (generated by audit_bad_images2.js)
 */

require('dotenv').config({ path: '.env.local' });
const { createClient } = require('@supabase/supabase-js');
const https = require('https');
const { randomUUID } = require('crypto');
const fs = require('fs');

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);
const GOOGLE_API_KEY = process.env.GOOGLE_PLACES_API_KEY;
const BUCKET = 'place-images';
const MAX_PHOTOS = 5;
const DELAY_MS = 300; // polite delay between API calls

// Progress tracking
const PROGRESS_FILE = 'tmp/fix_progress.json';

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function httpGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, { timeout: 15000 }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks) }));
    }).on('error', reject).on('timeout', () => reject(new Error('timeout')));
  });
}

async function searchPlace(query) {
  const body = JSON.stringify({
    textQuery: query,
    maxResultCount: 1,
    languageCode: 'en',
    regionCode: 'ET',
  });
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'places.googleapis.com',
      path: '/v1/places:searchText',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Goog-Api-Key': GOOGLE_API_KEY,
        'X-Goog-FieldMask': 'places.id,places.displayName,places.photos',
        'Content-Length': Buffer.byteLength(body),
      },
    };
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch (e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

async function fetchPhotoBytes(photoName) {
  const url = `https://places.googleapis.com/v1/${photoName}/media?maxHeightPx=800&maxWidthPx=1200&key=${GOOGLE_API_KEY}&skipHttpRedirect=true`;
  const r = await httpGet(url);
  if (r.status !== 200) return null;
  try {
    const j = JSON.parse(r.body.toString());
    if (j.photoUri) {
      const r2 = await httpGet(j.photoUri);
      return r2.status === 200 ? r2.body : null;
    }
  } catch {}
  return null;
}

async function uploadToSupabase(buffer, filename) {
  const { data, error } = await supabase.storage.from(BUCKET).upload(filename, buffer, {
    contentType: 'image/jpeg', upsert: true,
  });
  if (error) throw error;
  const { data: { publicUrl } } = supabase.storage.from(BUCKET).getPublicUrl(filename);
  return publicUrl;
}

async function clearOldImages(placeId) {
  const { error } = await supabase.from('PlaceImage')
    .delete()
    .eq('placeId', placeId)
    .neq('imageSource', 'google_places');
  if (error) console.log(`  ⚠ Could not clear old images: ${error.message}`);
}

async function insertImage(placeId, imageUrl, altText, priority) {
  const { error } = await supabase.from('PlaceImage').insert({
    id:             randomUUID(),
    placeId,
    imageUrl,
    mirroredUrl:    imageUrl,
    imageSource:    'google_places',
    altText,
    priority,
    status:         'APPROVED',
    isMirrored:     true,
    qualityScore:   80,
    imageTruthType: 'place_real',
  });
  if (error) throw error;
}

function buildSearchQuery(place) {
  const name = place.name;
  const type = place.type || '';
  // Append Ethiopia and city context for better matching
  const city = 'Addis Ababa';
  const typeHints = {
    restaurant: 'restaurant',
    cafe: 'cafe coffee',
    hotel: 'hotel',
    guesthouse: 'guesthouse lodge',
    museum: 'museum',
    park: 'park',
    landmark: 'landmark',
    market: 'market',
    resort: 'resort',
    transport: 'terminal station',
    'religious site': 'church cathedral mosque',
    apartment: 'apartment',
    coffee: 'coffee shop',
  };
  const hint = typeHints[type] || '';
  return `${name} ${hint} ${city} Ethiopia`.trim().replace(/\s+/g, ' ');
}

async function processPlace(place, index, total) {
  const query = buildSearchQuery(place);
  process.stdout.write(`[${index+1}/${total}] ${place.name} (${place.type})\n`);
  process.stdout.write(`  🔍 "${query}"\n`);

  let result;
  try {
    result = await searchPlace(query);
  } catch (e) {
    process.stdout.write(`  💥 Search failed: ${e.message}\n`);
    return { status: 'search_error', place: place.name };
  }

  const gPlace = result.places && result.places[0];
  if (!gPlace) {
    process.stdout.write(`  ℹ️  Not found on Google Places\n`);
    return { status: 'not_found', place: place.name };
  }
  if (!gPlace.photos || gPlace.photos.length === 0) {
    process.stdout.write(`  ℹ️  Found "${gPlace.displayName?.text}" — no photos\n`);
    return { status: 'no_photos', place: place.name };
  }

  const photos = gPlace.photos.slice(0, MAX_PHOTOS);
  process.stdout.write(`  📸 "${gPlace.displayName?.text}" — ${photos.length} photo(s)\n`);

  // Clear old non-google images
  await clearOldImages(place.id);

  let uploaded = 0;
  for (let i = 0; i < photos.length; i++) {
    const photoName = photos[i].name;
    const photoId = photoName.split('/').pop();
    const filename = `places/${place.id}/${photoId}.jpg`;
    try {
      const buf = await fetchPhotoBytes(photoName);
      if (!buf) { process.stdout.write(`  ⚠ Photo ${i+1}: no bytes\n`); continue; }
      const url = await uploadToSupabase(buf, filename);
      await insertImage(place.id, url, `${place.name} photo ${i+1}`, i);
      process.stdout.write(`  ✅ Photo ${i+1}/${photos.length} (${(buf.length/1024).toFixed(1)} KB)\n`);
      uploaded++;
    } catch (e) {
      process.stdout.write(`  💥 Photo ${i+1} failed: ${e.message}\n`);
    }
  }
  return { status: uploaded > 0 ? 'success' : 'upload_failed', uploaded, place: place.name };
}

async function main() {
  console.log('╔══════════════════════════════════════════════════════╗');
  console.log('║  AddisView — Bulk Image Fix Script                   ║');
  console.log('╚══════════════════════════════════════════════════════╝');

  if (!fs.existsSync('tmp/places_needing_images.json')) {
    console.error('❌ Run audit_bad_images2.js first to generate places_needing_images.json');
    process.exit(1);
  }

  const places = JSON.parse(fs.readFileSync('tmp/places_needing_images.json', 'utf8'));
  console.log(`\nLoaded ${places.length} places needing image fixes\n`);

  // Resume support: skip already-processed places
  let doneIds = new Set();
  if (fs.existsSync(PROGRESS_FILE)) {
    try {
      const prev = JSON.parse(fs.readFileSync(PROGRESS_FILE, 'utf8'));
      prev.filter(r => r.status === 'success').forEach(r => doneIds.add(r.id));
      console.log(`⏭  Resuming: ${doneIds.size} already done, skipping them\n`);
    } catch {}
  }

  const remaining = places.filter(p => !doneIds.has(p.id));
  console.log(`Processing ${remaining.length} remaining places...\n`);

  const results = [];
  const stats = { success: 0, not_found: 0, no_photos: 0, search_error: 0, upload_failed: 0 };

  for (let i = 0; i < remaining.length; i++) {
    const place = remaining[i];
    const result = await processPlace(place, i, remaining.length);
    result.id = place.id;
    results.push(result);
    stats[result.status] = (stats[result.status] || 0) + 1;

    // Save progress every 10 places
    if ((i + 1) % 10 === 0) {
      fs.writeFileSync(PROGRESS_FILE, JSON.stringify(results, null, 2));
      console.log(`  💾 Progress saved (${i+1}/${remaining.length})\n`);
    }

    await sleep(DELAY_MS);
  }

  fs.writeFileSync(PROGRESS_FILE, JSON.stringify(results, null, 2));
  fs.writeFileSync('tmp/fix_results.json', JSON.stringify(results, null, 2));

  console.log('\n' + '═'.repeat(54));
  console.log('SUMMARY');
  console.log('═'.repeat(54));
  console.log(`✅ Successfully fixed:  ${stats.success || 0}`);
  console.log(`❌ Not found on Google: ${stats.not_found || 0}`);
  console.log(`📷 Found but no photos: ${stats.no_photos || 0}`);
  console.log(`💥 Search errors:       ${stats.search_error || 0}`);
  console.log(`⚠️  Upload failures:     ${stats.upload_failed || 0}`);
  console.log('═'.repeat(54));
  console.log(`\nResults saved to tmp/fix_results.json`);
}

main().catch(console.error);
